import React from 'react';

function PricingTable() {
  const pricingItems = [
    {
      category: "HÀNG PHỔ THÔNG",
      items: "Quần áo, giày dép, đồ gia dụng",
      price: "260.000 VNĐ/kg",
      highlight: false
    },
    {
      category: "TP CHỨC NĂNG",
      items: "Sữa, Đồ em bé",
      price: "280.000 VNĐ/kg",
      highlight: false
    },
    {
      category: "MỸ PHẨM",
      items: "Nước hoa, Túi xách hiệu",
      price: "300.000 VNĐ/kg",
      highlight: true
    },
    {
      category: "ĐIỆN TỬ CAO CẤP",
      items: "Laptop, iPhone",
      price: "Liên hệ báo giá",
      highlight: false
    },
  ];

  return (
    <section className="py-28 px-6 bg-surface relative" id="pricing">
      <div className="container mx-auto text-center">
        <h2 className="text-4xl md:text-5xl font-serif font-extrabold text-primary-dark tracking-tight leading-tight uppercase">
            Bảng giá dịch vụ ưu đãi
        </h2>
        <p className="mt-6 text-lg text-gray-500 font-sans font-light max-w-2xl mx-auto leading-relaxed">
            Chúng tôi cam kết bảng giá minh bạch, không phát sinh chi phí ẩn cho từng loại mặt hàng cụ thể.
        </p>

        <div className="mt-20 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
          {pricingItems.map((item, index) => (
            <div key={index} className={`bg-white p-10 rounded-2xl shadow-soft border ${item.highlight ? 'border-primary-accent border-2' : 'border-gray-100'} flex flex-col justify-between transition-all transform hover:shadow-2xl relative overflow-hidden group`}>
              {item.highlight && (
                <div className="absolute top-0 right-0 bg-primary-accent text-white py-1 px-4 text-xs font-bold uppercase tracking-widest rounded-bl-xl shadow-md">
                  Hot
                </div>
              )}

              <div className="z-10 text-center">
                <h3 className="text-sm font-sans font-bold text-gray-400 tracking-widest mb-2">{item.category}</h3>
                <p className="text-gray-500 text-xs italic mb-8 font-light leading-relaxed">({item.items})</p>
                <p className="text-3xl font-serif font-extrabold text-primary-dark tracking-tighter transition-colors group-hover:text-primary-accent leading-none">
                  {item.price}
                </p>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-16 p-10 bg-white border border-primary-accent shadow-soft text-primary-dark rounded-2xl max-w-2xl mx-auto relative overflow-hidden flex flex-col items-center">
          <div className="absolute -left-4 -top-4 w-24 h-24 bg-primary-accent/5 rounded-full z-0 transform -scale-x-100"></div>
          <div className="absolute -right-4 -bottom-4 w-24 h-24 bg-primary-accent/5 rounded-full z-0"></div>

          <div className="z-10 relative">
            <h4 className="text-lg font-sans font-bold uppercase tracking-widest text-primary-accent mb-4">Ưu đãi cực đặc biệt:</h4>
            <p className="text-2xl font-serif font-extrabold text-primary-dark leading-tight">
              Giảm ưu đãi ngay xuống <span className="underline decoration-primary-accent decoration-4 underline-offset-8">250.000đ/kg</span> cho kiện hàng trên 5kg!
            </p>
          </div>
        </div>
      </div>
    </section>
  );
}

export default PricingTable;
